"$token = "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"
$paths = @(
    "C:\Users\Gustavo\.gemini\config\mcp_config.json",
    "C:\Users\Gustavo\.gemini\antigravity-ide\mcp_config.json",
    "C:\Users\Gustavo\.gemini\antigravity-backup\mcp_config.json"
)

foreach ($path in $paths) {
    if (Test-Path $path) {
        $json = Get-Content -Raw -Path $path | ConvertFrom-Json
        if ($json.mcpServers.'github-mcp-server') {
            $json.mcpServers.'github-mcp-server'.env.GITHUB_PERSONAL_ACCESS_TOKEN = $token
            $json | ConvertTo-Json -Depth 10 | Set-Content -Path $path
            Write-Output "Updated $path"
        } else {
            Write-Output "github-mcp-server section not found in $path"
        }
    } else {
        Write-Output "File not found: $path"
    }
}

[Environment]::SetEnvironmentVariable("GITHUB_PERSONAL_ACCESS_TOKEN", $token, "User")
